### Change 1 — New handler function (inserted after `common_chat_params_init_gigachat_v3` ~line 1517, before `namespace workaround`)

```cpp
static common_chat_params common_chat_params_init_mistral_instruct_v3(
        const common_chat_template & tmpl,
        const autoparser::generation_params & inputs) {
    common_chat_params data;

    std::string system_content;
    std::string prompt;
    bool        first_user = true;

    for (const auto & msg : inputs.messages) {
        auto role    = msg.value("role", "");
        auto content = msg.value("content", "");

        if (role == "system") {
            system_content = content;
        } else if (role == "user") {
            if (first_user) {
                if (!system_content.empty()) {
                    prompt += "[INST] " + system_content + "\n" + content + " [/INST]";
                } else {
                    prompt += "[INST] " + content + " [/INST]";
                }
                first_user = false;
            } else {
                prompt += "[INST] " + content + " [/INST]";
            }
        } else if (role == "assistant") {
            prompt += " " + content + "</s>";
        }
    }

    data.prompt = (tmpl.bos_token().empty() ? "" : tmpl.bos_token()) + prompt;
    data.format = COMMON_CHAT_FORMAT_CONTENT_ONLY;
    return data;
}
```

### Change 2 — Detection block in `common_chat_try_specialized_template()` (just before `return std::nullopt;` ~line 1689)

```cpp
